'use client';

import { useMemo, useState } from 'react';
import { useParams } from 'next/navigation';
import { EmptyStateCard, PageHeader, Tabs } from '../../../components/ui';
import {
  activeMockUser,
  canView,
  canManageStudent,
  getStudentById,
  getStudentCalendarEvents,
  type MockStudent,
  type UserRole,
} from '../../../mocks';
import { StudentAchievementsRow, StudentCalendarTab, StudentHeaderCard, StudentProfileTab, StudentScheduleTab } from './sections';
import styles from './page.module.scss';

export default function StudentDetailsPage() {
  const params = useParams<{ studentId: string }>();
  const studentId = params?.studentId;
  const student = studentId ? getStudentById(studentId) : undefined;

  if (!canView('dashboard', activeMockUser.role)) return null;
  const allowedRoles = activeMockUser.role === 'teacher' || activeMockUser.role === 'admin' || activeMockUser.role === 'super-admin';
  if (!allowedRoles) {
    return <EmptyStateCard title="No permission" description="Students section is not available for your role." />;
  }
  if (!student) {
    return <EmptyStateCard title="Student not found" description="Check the student link and try again." />;
  }
  const canManage = canManageStudent(activeMockUser, student);
  if (!canManage) {
    return <EmptyStateCard title="No permission" description="You cannot manage this student." />;
  }

  const [tab, setTab] = useState<'profile' | 'calendar' | 'schedule'>('profile');
  const [studentForm, setStudentForm] = useState<MockStudent>(student);
  const [events, setEvents] = useState(getStudentCalendarEvents(student.id));
  const [lessonType, setLessonType] = useState('grammar');
  const [date, setDate] = useState('');
  const [time, setTime] = useState('');
  const [comment, setComment] = useState('');

  const pageSubtitle = useMemo(
    () => `Manage student profile, calendar and scheduling · ${activeMockUser.role as UserRole}`,
    [],
  );

  return (
    <div className={`${styles.page} container container--page`}>
      <PageHeader
        className={styles.pageHeader}
        titleClassName={styles.pageTitle}
        subtitleClassName={styles.pageSub}
        title="Student Details"
        subtitle={pageSubtitle}
      />

      <StudentHeaderCard student={studentForm} />
      <StudentAchievementsRow student={studentForm} />

      <Tabs
        value={tab}
        onValueChange={setTab}
        ariaLabel="Student tabs"
        listClassName={styles.tabsRow}
        triggerClassName={styles.tabBtn}
        activeTriggerClassName={styles.tabActive}
        panelClassName={styles.tabContent}
        items={[
          {
            value: 'profile',
            label: 'Profile',
            panel: (
              <StudentProfileTab
                student={studentForm}
                onChange={setStudentForm}
                canEdit={canManage}
                onSave={() => {}}
              />
            ),
          },
          {
            value: 'calendar',
            label: 'Calendar',
            panel: <StudentCalendarTab events={events} />,
          },
          {
            value: 'schedule',
            label: 'Schedule',
            panel: (
              <StudentScheduleTab
                canEdit={canManage}
                lessonType={lessonType}
                setLessonType={setLessonType}
                date={date}
                setDate={setDate}
                time={time}
                setTime={setTime}
                comment={comment}
                setComment={setComment}
                onPlan={() => {
                  const newEvent = {
                    id: `evt-local-${Date.now()}`,
                    title: `${lessonType.charAt(0).toUpperCase() + lessonType.slice(1)} Lesson`,
                    type: lessonType as 'grammar' | 'vocabulary' | 'speaking' | 'listening',
                    date,
                    time,
                    duration: 55,
                    teacherId: studentForm.teacherId,
                    teacherName: studentForm.teacherName,
                    studentId: studentForm.id,
                    studentName: studentForm.fullName,
                    status: 'pending' as const,
                  };
                  setEvents((prev) => [...prev, newEvent]);
                  setDate('');
                  setTime('');
                  setComment('');
                  setTab('calendar');
                }}
              />
            ),
          },
        ]}
      />
    </div>
  );
}
